/**
 * Code node: Prepare CV Payload
 * - Ensures the same item carries: cv_text + file_id + file_name
 * - Trims/normalizes text to keep the classifier stable
 */

let text = $json.text || "";
text = String(text).replace(/\r/g, "\n");
text = text.replace(/\n{3,}/g, "\n\n").trim();

const maxChars = 30000;
if (text.length > maxChars) text = text.slice(0, maxChars);

// metadata from Drive download node (n8n usually provides these on the same item)
const file_id = $json.id ?? $json.fileId ?? $json.file_id ?? null;
const file_name = $json.name ?? $json.fileName ?? $json.file_name ?? null;

return [
  {
    json: {
      file_id,
      file_name,
      cv_text: text
    }
  }
];

/**
 * Code node: Map classification -> rate grid
 *
 * Output:
 * - role_family
 * - level
 * - buy_min, buy_mid, buy_max
 * - margin_min, margin_max
 * - sell_min, sell_mid, sell_max
 * - plus derived point estimates (buy_est, margin_est, sell_est)
 *
 * Notes:
 * - This is intentionally SIMPLE and deterministic.
 * - Uses your provided grid exactly.
 */

function asNum(x) {
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
}

function clamp(n, lo, hi) {
  if (n == null) return null;
  if (n < lo) return lo;
  if (n > hi) return hi;
  return n;
}

// Parse the model response (OpenAI node returns content in different shapes depending on n8n version)
let raw = $json;
let content = raw.message?.content ?? raw.choices?.[0]?.message?.content ?? raw.text ?? raw.content ?? null;

if (content == null) {
  // Sometimes n8n places response directly on json
  content = raw.data ?? null;
}

let parsed;
try {
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  throw new Error('Classifier did not return valid JSON. Raw: ' + String(content).slice(0, 400));
}

const role_family = String(parsed.role_family || '').trim();
const level = clamp(asNum(parsed.level), 1, 5);

