    sell_min: 858, sell_mid: 901, sell_max: 987,
    extra_a: 815, extra_b: 729
  }
];

let row = GRID.find(r => r.role_family.toLowerCase() === role_family.toLowerCase());
if (!row && role_family) {
  const rf = role_family.toLowerCase();
  row = GRID.find(r => rf.includes(r.role_family.toLowerCase()) || r.role_family.toLowerCase().includes(rf));
}

if (!row) {
  throw new Error('Role family not recognized: "' + role_family + '".');
}

const buy_est = row.buy_mid;
const margin_est = (row.margin_min + row.margin_max) / 2;
const sell_est = row.sell_mid;

return [
  {
    json: {
      file_id: $node['Code - Prepare CV Payload']?.json?.file_id ?? null,
      file_name: $node['Code - Prepare CV Payload']?.json?.file_name ?? null,
      cv_full_name: parsed.full_name ?? null,
